import { Injectable, signal, computed } from '@angular/core';
import { CartItem, Product } from '../models';

/**
 * Shopping cart service.
 *
 * Data contract: `items` is a signal<CartItem[]> holding the current cart. Starts empty;
 * populated interactively via addItem(). The mockup_cleaner keeps it as signal<CartItem[]>([]);
 * the service_agent wires it to cart-api.service.ts (GET /cart, POST /cart/items, ...).
 */
@Injectable({ providedIn: 'root' })
export class CartService {
  readonly items = signal<CartItem[]>([]);

  readonly count = computed(() => this.items().reduce((sum, i) => sum + i.qty, 0));
  readonly subtotalCents = computed(() =>
    this.items().reduce((sum, i) => sum + i.qty * i.product.priceCents, 0),
  );

  addItem(product: Product, qty = 1): void {
    this.items.update((list) => {
      const existing = list.find((i) => i.productId === product.id);
      if (existing) {
        return list.map((i) =>
          i.productId === product.id
            ? { ...i, qty: Math.min(i.qty + qty, product.stockQty) }
            : i,
        );
      }
      return [
        ...list,
        { id: `ci-${product.id}`, productId: product.id, qty, product },
      ];
    });
  }

  updateQty(itemId: string, qty: number): void {
    if (qty <= 0) {
      this.removeItem(itemId);
      return;
    }
    this.items.update((list) =>
      list.map((i) =>
        i.id === itemId ? { ...i, qty: Math.min(qty, i.product.stockQty) } : i,
      ),
    );
  }

  removeItem(itemId: string): void {
    this.items.update((list) => list.filter((i) => i.id !== itemId));
  }

  clear(): void {
    this.items.set([]);
  }
}
